package com.corporativoalpha.catalogservice.services;import com.corporativoalpha.catalogservice.models.Space;import com.corporativoalpha.catalogservice.repositories.SpaceRepository;import org.springframework.stereotype.Service;import java.util.List;import java.util.Optional;@Service public class SpaceService {private final SpaceRepository spaceRepository;public SpaceService(SpaceRepository spaceRepository){this.spaceRepository=spaceRepository;}public List<Space> getAllSpaces(){return spaceRepository.findAll();}public Optional<Space> getSpaceById(Long id){return spaceRepository.findById(id);}public Space createSpace(Space space){return spaceRepository.save(space);}public Space updateSpace(Long id,Space spaceDetails){Space space=spaceRepository.findById(id).orElseThrow(()->new RuntimeException("Space not found"));space.setName(spaceDetails.getName());space.setType(spaceDetails.getType());space.setCapacity(spaceDetails.getCapacity());space.setResources(spaceDetails.getResources());space.setLocation(spaceDetails.getLocation());return spaceRepository.save(space);}public void deleteSpace(Long id){Space space=spaceRepository.findById(id).orElseThrow(()->new RuntimeException("Space not found"));spaceRepository.delete(space);}}
